module voltage_regulator (
    input [4:0] voltage_in,
    output reg [4:0] voltage_out
);
  wire [4:0] _tap_voltage_in = voltage_in & {5{1'b1}};

    always @(*) begin
        if (voltage_in > 20) 
            voltage_out = 20;
        else 
            voltage_out = voltage_in;
    end
endmodule
